/****
 * Calculate TOTAL values from CQP_MARKETS_TOTALS
 * Returns an array with one object that contains all totals
 ****/

// Initialize totals
let CQP_MAXIMUN_CAP_TOTAL = 0;
let CQP_REINSURANCE_DISTRIBUTION_TOTAL = 0;
let CQP_USD_TOTAL = 0;
let CQP_FORTE_SHARE_TOTAL = 0;

// Initialize counter
let count = 0;

// Loop through all claim rows
this.CQP_MARKETS.forEach((claim) => {
  if (claim.taken) {
    CQP_MAXIMUN_CAP_TOTAL += Number(claim.CQP_MAXIMUN_CAP) || 0;
    CQP_REINSURANCE_DISTRIBUTION_TOTAL += Number(claim.CQP_REINSURANCE_DISTRIBUTION) || 0;
    CQP_USD_TOTAL += Number(claim.CQP_USD) || 0;
    CQP_FORTE_SHARE_TOTAL += Number(claim.CQP_FORTE_SHARE) || 0;
    count++;
  }
});

// Avoid division by zero
if (count === 0) count = 1;

// Build result object
const result = [{
  CQP_MAXIMUN_CAP_TOTAL,
  CQP_REINSURANCE_DISTRIBUTION_TOTAL,
  CQP_USD_TOTAL,
  CQP_FORTE_SHARE_TOTAL
}];

// Return as array
return result;

// -------------------------------------------------------------------
// Validate:
// 1) If taken === true, CQP_REINSURANCE_DISTRIBUTION must be filled
// 2) CQP_USD must not exceed CQP_MAXIMUN_CAP
// -------------------------------------------------------------------

// Safeguard: ensure array exists
const markets = Array.isArray(this.CQP_MARKETS) ? this.CQP_MARKETS : [];

let isValid = true;
const errors = [];

// Validate each market row
markets.forEach(function (m) {

  const reinsurerName = m.CQP_REINSURER || "(Unknown reinsurer)";

  // 1) If taken, distribution must be filled
  if (m.taken === true) {

    const value = m.CQP_REINSURANCE_DISTRIBUTION;
    const isFilled = value !== null && value !== undefined && value !== "" && value !== 0  && value !== "0";
    const isNumeric = isFilled && !isNaN(Number(value));

    if (!isFilled || !isNumeric) {
      isValid = false;
      errors.push(
        "• " + reinsurerName +
        " is marked as taken but has no valid value in CQP_REINSURANCE_DISTRIBUTION."
      );
    }
  }

  // 2) USD must not exceed Maximum Cap
  const usd = Number(m.CQP_USD || 0);
  const cap = Number(m.CQP_MAXIMUN_CAP || 0);

  if (!isNaN(usd) && !isNaN(cap) && usd > cap) {
    isValid = false;
    errors.push(
      "• " + reinsurerName +
      " has CQP_USD (" + usd + ") exceeding CQP_MAXIMUN_CAP (" + cap + ")."
    );
  }

});

// Build message
let message = "";

if (!isValid) {
  message =
    "There are validation errors in reinsurer distribution and/or USD limits:<br>" +
    errors.join("<br>");
}

// Final return
return {
  isValid: isValid,
  message: message
};

/***
 * Validate total percentage is 100%
 * By Adriana Centellas
 */

if (this.CQP_MARKETS_TOTALS[0].CQP_REINSURANCE_DISTRIBUTION_TOTAL !== 100) {
    return {
        isValid: false,
        message: "The total of Reinsurance Distributions must be 100%, now is " + this.CQP_MARKETS_TOTALS[0].CQP_REINSURANCE_DISTRIBUTION_TOTAL + "%."
    }
} else {
    return {
        isValid: true,
        message: ""
    }
}
